$src = "C:\Users\perur\Downloads\EFAR_final\efar_final"
$dst = "C:\Users\perur\Downloads\fsa-assignment"

# Copy top-level files
Copy-Item "$src\.gitignore" "$dst\.gitignore" -Force
Copy-Item "$src\deployment.md" "$dst\deployment.md" -Force

# Copy design/ (all contents)
Copy-Item "$src\design" "$dst\design" -Recurse -Force

# Copy backend/ excluding node_modules
$backendItems = Get-ChildItem "$src\backend" | Where-Object { $_.Name -ne "node_modules" }
New-Item -ItemType Directory -Force "$dst\backend" | Out-Null
foreach ($item in $backendItems) {
    Copy-Item $item.FullName "$dst\backend\$($item.Name)" -Recurse -Force
}

# Copy frontend/ excluding node_modules and .env.development
$frontendItems = Get-ChildItem "$src\frontend" | Where-Object { $_.Name -ne "node_modules" -and $_.Name -ne ".env.development" }
New-Item -ItemType Directory -Force "$dst\frontend" | Out-Null
foreach ($item in $frontendItems) {
    Copy-Item $item.FullName "$dst\frontend\$($item.Name)" -Recurse -Force
}

Write-Host "Done copying"

