$client = "C:\Users\perur\Downloads\EFAR_final\efar_final\client"
$frontend = "C:\Users\perur\Downloads\EFAR_final\efar_final\frontend"

# Copy everything from frontend/ into client/ (merge, don't overwrite existing)
Get-ChildItem $frontend | ForEach-Object {
    $dest = Join-Path $client $_.Name
    if (-not (Test-Path $dest)) {
        Copy-Item $_.FullName $dest -Recurse -Force
        Write-Host "Copied: $($_.Name)"
    } else {
        Write-Host "Skipped (already exists): $($_.Name)"
    }
}

# Delete the now-redundant frontend/ folder
Remove-Item $frontend -Recurse -Force -Confirm:$false
Write-Host "Deleted frontend/"

# Rename client/ to frontend/
Rename-Item $client "frontend"
Write-Host "Renamed client/ to frontend/"
